// Nó 02: Valida HMAC, filtra mensagens inválidas e verifica ia_ativa + kill_switch
const crypto = require('crypto');

const body = $input.first().json;
const headers = body.headers || {};

// --- HMAC validation ---
const secret = $env.EVOLUTION_HMAC_SECRET;
const sig = headers['x-evolution-signature'] || headers['X-Evolution-Signature'] || '';
if (secret && sig) {
  const payload = JSON.stringify(body.body !== undefined ? body.body : body);
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(payload).digest('hex');
  if (expected !== sig) {
    throw new Error('HMAC inválido — requisição rejeitada');
  }
}

// --- Filtrar fromMe ---
const fromMe = body?.data?.key?.fromMe;
if (fromMe === true) {
  return [{ json: { action: 'stop', reason: 'fromMe' } }];
}

// --- Filtrar evento ---
const event = body?.event || '';
if (!['messages.upsert', 'message'].includes(event)) {
  return [{ json: { action: 'stop', reason: 'eventoIgnorado' } }];
}

// --- Extrair dados da mensagem ---
const msgData = body?.data?.message || {};
const remotejid = body?.data?.key?.remoteJid || '';
const pushName = body?.data?.pushName || '';

if (!remotejid) {
  return [{ json: { action: 'stop', reason: 'semRemotejid' } }];
}

const conversation =
  msgData?.conversation ||
  msgData?.extendedTextMessage?.text ||
  '';

// --- Detectar mídia ---
if (!conversation) {
  const isMedia = !!(msgData?.imageMessage || msgData?.audioMessage || msgData?.videoMessage || msgData?.documentMessage);
  if (isMedia) {
    return [{ json: { action: 'media_only', remotejid, pushName } }];
  }
  return [{ json: { action: 'stop', reason: 'conteudoVazio' } }];
}

// --- Verificar kill_switch e ia_ativa via Supabase ---
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;
const sbHeaders = { apikey: supabaseKey, Authorization: `Bearer ${supabaseKey}` };

const configRes = await fetch(
  `${supabaseUrl}/rest/v1/clientes_config?select=kill_switch&limit=1`,
  { headers: sbHeaders }
);
const configData = await configRes.json();
if (configData?.[0]?.kill_switch === true) {
  return [{ json: { action: 'stop', reason: 'killSwitch' } }];
}

const leadRes = await fetch(
  `${supabaseUrl}/rest/v1/leads?select=ia_ativa&remotejid=eq.${encodeURIComponent(remotejid)}&limit=1`,
  { headers: sbHeaders }
);
const leadData = await leadRes.json();
const lead = Array.isArray(leadData) ? leadData[0] : null;

// Lead existe e ia_ativa = FALSE → humano no controle, IARA para
if (lead && lead.ia_ativa === false) {
  return [{ json: { action: 'stop', reason: 'iaInativa' } }];
}

// Lead não existe (null) OU ia_ativa = TRUE → processa
return [{ json: { action: 'process', remotejid, pushName, content: conversation } }];

