// Nó 05: Persistir msg ANTES de chamar Anthropic (regra canônica)
// 1. UPSERT em leads (cria se novo, atualiza updated_at se existe)
// 2. INSERT em chat_messages (role=user)
const remotejid = $input.first().json.remotejid;
const pushName = $input.first().json.pushName;
const content = $input.first().json.content;

const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;
const h = {
  apikey: supabaseKey,
  Authorization: `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
};

// UPSERT lead
const leadRes = await fetch(`${supabaseUrl}/rest/v1/leads`, {
  method: 'POST',
  headers: { ...h, Prefer: 'resolution=merge-duplicates' },
  body: JSON.stringify({ remotejid, nome: pushName || null }),
});
if (!leadRes.ok && leadRes.status !== 409) {
  const err = await leadRes.text();
  throw new Error(`Falha ao persistir lead (${leadRes.status}): ${err}`);
}

// INSERT mensagem do lead
const msgRes = await fetch(`${supabaseUrl}/rest/v1/chat_messages`, {
  method: 'POST',
  headers: h,
  body: JSON.stringify({ remotejid, role: 'user', content }),
});
if (!msgRes.ok) {
  const err = await msgRes.text();
  throw new Error(`Falha ao persistir mensagem (${msgRes.status}): ${err}`);
}

return [{ json: { remotejid, pushName, content } }];

// Nó 06: Carrega histórico (últimas 20 msgs) e perfil do lead do Supabase
const remotejid = $input.first().json.remotejid;
const pushName = $input.first().json.pushName;
const content = $input.first().json.content;

const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;
const sbHeaders = { apikey: supabaseKey, Authorization: `Bearer ${supabaseKey}` };

// Histórico: últimas 20 msgs em ordem DESC, depois reverter para cronológica
const histRes = await fetch(
  `${supabaseUrl}/rest/v1/chat_messages?remotejid=eq.${encodeURIComponent(remotejid)}&order=created_at.desc&limit=20&select=role,content`,
  { headers: sbHeaders }
);
const histData = await histRes.json();
const history = Array.isArray(histData) ? histData.reverse() : [];

// Perfil do lead
const perfilRes = await fetch(
  `${supabaseUrl}/rest/v1/leads_perfil?remotejid=eq.${encodeURIComponent(remotejid)}&select=objetivo,historico_treino,restricoes,frequencia,turno_preferido&limit=1`,
  { headers: sbHeaders }
);
const perfilData = await perfilRes.json();
const perfil = Array.isArray(perfilData) && perfilData.length > 0 ? perfilData[0] : {};

return [{ json: { remotejid, pushName, content, history, perfil } }];

// Nó 07: Chama Anthropic Sonnet 4.6 com system prompt + 3 tools.
// Executa loop de tool_use até 5 iterações.
// Regra: só retorna após stop_reason=end_turn (texto final).

const fs = require('fs');

const input = $input.first().json;
const remotejid = input.remotejid;
const pushName = input.pushName;
const content = input.content;
const history = input.history || [];
const perfil = input.perfil || {};

// --- Carregar system prompt do arquivo ---
const promptPath = $env.IARA_SYSTEM_PROMPT_PATH ||
  '/home/node/greenfield-iara-chat/prompts/system_prompt_iara_v1.txt';
let systemPrompt;
try {
  systemPrompt = fs.readFileSync(promptPath, 'utf8');
} catch (e) {
  throw new Error(`Não foi possível carregar system prompt: ${promptPath} — ${e.message}`);
}

// --- Injetar perfil salvo no system prompt ---
const camposPerfil = ['objetivo', 'historico_treino', 'restricoes', 'frequencia', 'turno_preferido'];
const perfilLines = camposPerfil.filter(c => perfil[c]).map(c => `${c}: ${perfil[c]}`);
const fullSystem = perfilLines.length > 0
  ? systemPrompt + '\n\n[PERFIL SALVO DO LEAD]\n' + perfilLines.join('\n')
  : systemPrompt;

// --- Montar array de mensagens a partir do histórico ---
// chat_messages role: 'user' | 'assistant' | 'system' | 'tool'
// Anthropic aceita: 'user' | 'assistant'
// Msgs role='system' e role='tool' do banco são notas internas — não enviar ao LLM
const messages = [];
for (const msg of history) {
  if (msg.role === 'user' || msg.role === 'assistant') {
    messages.push({ role: msg.role, content: msg.content });
  }
  // system e tool do banco: skip (são metadados internos do n8n, não do LLM)
}

// --- Tool definitions (3 tools, sem mais) ---
const tools = [
  {
    name: 'salvar_perfil',
    description: 'Salva dados de qualificação do lead conforme aparecem na conversa. Use sempre que o lead mencionar objetivo, histórico, restrição, frequência ou turno preferido. Não pergunte ativamente — só salve quando o dado já apareceu naturalmente.',
    input_schema: {
      type: 'object',
      properties: {
        objetivo: { type: 'string', description: 'Objetivo principal. Ex: "emagrecer", "ganhar massa", "saúde", "reabilitação"' },
        historico_treino: { type: 'string', description: 'Experiência prévia. Ex: "nunca treinou", "treina há 2 anos", "parou faz 6 meses"' },
        restricoes: { type: 'string', description: 'Lesões, dores ou restrições médicas mencionadas' },
        frequencia: { type: 'string', description: 'Frequência desejada. Ex: "3x por semana", "4x", "todos os dias"' },
        turno_preferido: { type: 'string', description: 'Turno. Ex: "manhã", "tarde", "noite", "final de tarde"' }
      }
    }
  },
  {
    name: 'agendar_aula_experimental',
    description: 'Agenda Aula Experimental gratuita após o lead confirmar dia e horário específico. NUNCA invente horário — só agende dentro do funcionamento da academia (Seg-Sex 5h-21h, Sáb 8h-13h, Dom fechado).',
    input_schema: {
      type: 'object',
      properties: {
        horario_iso: { type: 'string', description: 'Data e hora ISO 8601 com timezone Campo Grande (UTC-4). Ex: "2026-05-20T18:00:00-04:00"' },
        nome_lead: { type: 'string', description: 'Nome do lead conforme ele se apresentou' }
      },
      required: ['horario_iso', 'nome_lead']
    }
  },
  {
    name: 'handoff_humano',
    description: 'Transfere conversa para atendimento humano via Chatwoot. Use OBRIGATORIAMENTE quando: lead pedir desconto, cancelamento, questão financeira (boleto, reembolso, inadimplência), lead pedir explicitamente para falar com humano, ou surgir situação fora do escopo.',
    input_schema: {
      type: 'object',
      properties: {
        motivo: {
          type: 'string',
          enum: ['desconto', 'cancelamento', 'financeiro', 'pedido_explicito', 'outro'],
          description: 'Categoria do motivo do handoff'
        },
        contexto: { type: 'string', description: 'Resumo de 1-2 frases do que o lead quer' }
      },
      required: ['motivo', 'contexto']
    }
  }
];

// --- Variáveis de ambiente ---
const anthropicKey = $env.ANTHROPIC_API_KEY;
const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;
const chatwootUrl = $env.CHATWOOT_URL;
const chatwootToken = $env.CHATWOOT_API_TOKEN;
const chatwootInboxId = $env.CHATWOOT_INBOX_ID;

// --- Executores de tools ---
async function executeSalvarPerfil(toolInput) {
  const payload = { remotejid };
  const campos = ['objetivo', 'historico_treino', 'restricoes', 'frequencia', 'turno_preferido'];
  for (const c of campos) {
    if (toolInput[c] !== undefined) payload[c] = toolInput[c];
  }
  const res = await fetch(`${supabaseUrl}/rest/v1/leads_perfil`, {
    method: 'POST',
    headers: {
      apikey: supabaseKey,
      Authorization: `Bearer ${supabaseKey}`,
      'Content-Type': 'application/json',
      Prefer: 'resolution=merge-duplicates',
    },
    body: JSON.stringify(payload),
  });
  if (!res.ok) {
    const err = await res.text();
    throw new Error(`salvar_perfil Supabase error ${res.status}: ${err}`);
  }
  return { status: 'ok', campos_atualizados: Object.keys(payload).filter(k => k !== 'remotejid') };
}

async function executeAgendarAulaExperimental(toolInput) {
  const accessToken = $env.GOOGLE_CALENDAR_ACCESS_TOKEN || '';
  const calendarId = $env.GOOGLE_CALENDAR_ID || 'primary';

  if (!accessToken) {
    return {
      status: 'erro_config',
      mensagem: 'Agenda não configurada. Entre em contato com nossa equipe para confirmar horário.'
    };
  }

  const start = new Date(toolInput.horario_iso);
  const end = new Date(start.getTime() + 60 * 60 * 1000);
  const event = {
    summary: `Aula Experimental — ${toolInput.nome_lead}`,
    description: `Agendado via IARA Chat.\nLead: ${toolInput.nome_lead}\nWhatsApp: ${remotejid}`,
    start: { dateTime: start.toISOString(), timeZone: 'America/Campo_Grande' },
    end: { dateTime: end.toISOString(), timeZone: 'America/Campo_Grande' },
  };

  let calRes;
  try {
    calRes = await fetch(
      `https://www.googleapis.com/calendar/v3/calendars/${encodeURIComponent(calendarId)}/events`,
      {
        method: 'POST',
        headers: { Authorization: `Bearer ${accessToken}`, 'Content-Type': 'application/json' },
        body: JSON.stringify(event),
      }
    );
  } catch (e) {
    return { status: 'erro_calendar', mensagem: 'Tive problema para acessar a agenda. Vou te conectar com nossa equipe para confirmar o horário.' };
  }

  if (calRes.status === 409) {
    return { status: 'ocupado', sugestao_proximo: 'Verifique disponibilidade com a equipe.' };
  }
  if (!calRes.ok) {
    return { status: 'erro_calendar', mensagem: 'Tive problema para acessar a agenda. Vou te conectar com nossa equipe para confirmar o horário.' };
  }

  const calData = await calRes.json();
  return { status: 'ok', evento_id: calData.id, horario_confirmado: toolInput.horario_iso };
}

async function executeHandoffHumano(toolInput) {
  const msgLead = 'Vou te conectar com nosso atendimento agora — em instantes alguém vai te responder por aqui. 🤝';

  // 1. Atualiza ia_ativa = FALSE ANTES de criar conversa no Chatwoot
  await fetch(
    `${supabaseUrl}/rest/v1/leads?remotejid=eq.${encodeURIComponent(remotejid)}`,
    {
      method: 'PATCH',
      headers: {
        apikey: supabaseKey,
        Authorization: `Bearer ${supabaseKey}`,
        'Content-Type': 'application/json',
        Prefer: 'return=minimal',
      },
      body: JSON.stringify({ ia_ativa: false }),
    }
  );

  // 2. Cria/atualiza conversa no Chatwoot
  let conversaId = 0;
  if (chatwootUrl && chatwootToken && chatwootInboxId) {
    try {
      const phone = remotejid.replace(/@s\.whatsapp\.net$|@c\.us$/g, '');
      const ctHeaders = { api_access_token: chatwootToken, 'Content-Type': 'application/json' };

      // Cria contato (Chatwoot deduplica pelo identifier)
      const contactRes = await fetch(`${chatwootUrl}/api/v1/accounts/1/contacts`, {
        method: 'POST',
        headers: ctHeaders,
        body: JSON.stringify({
          name: pushName || phone,
          phone_number: `+${phone}`,
          identifier: remotejid,
        }),
      });
      const contactData = await contactRes.json();
      const contactId = contactData?.id || contactData?.contact?.id;

      if (contactId) {
        const convRes = await fetch(`${chatwootUrl}/api/v1/accounts/1/conversations`, {
          method: 'POST',
          headers: ctHeaders,
          body: JSON.stringify({
            contact_id: contactId,
            inbox_id: parseInt(chatwootInboxId, 10),
            additional_attributes: {
              motivo_handoff: toolInput.motivo,
              contexto_iara: toolInput.contexto,
              remotejid,
            },
          }),
        });
        const convData = await convRes.json();
        conversaId = convData?.id || 0;
      }
    } catch (e) {
      // Chatwoot falhou, mas ia_ativa já foi marcada FALSE — não lança erro
      console.error('Chatwoot handoff error:', e.message);
    }
  }

  return { status: 'ok', conversa_chatwoot_id: conversaId, mensagem_para_lead: msgLead };
}

// --- Loop principal Anthropic (até 5 iterações) ---
const MAX_ITER = 5;
const currentMessages = [...messages];
let finalText = '';

for (let iter = 0; iter < MAX_ITER; iter++) {
  let res;
  try {
    res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': anthropicKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json',
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-6',
        max_tokens: 1024,
        system: fullSystem,
        messages: currentMessages,
        tools,
      }),
    });
  } catch (e) {
    // Retry único após 2s (política da ARQUITETURA.md)
    await new Promise(r => setTimeout(r, 2000));
    res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': anthropicKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json',
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-6',
        max_tokens: 1024,
        system: fullSystem,
        messages: currentMessages,
        tools,
      }),
    });
  }

  if (!res.ok) {
    const errBody = await res.text();
    throw new Error(`Anthropic API ${res.status}: ${errBody}`);
  }

  const data = await res.json();

  // Adiciona resposta do assistant ao histórico de turno
  currentMessages.push({ role: 'assistant', content: data.content });

  if (data.stop_reason === 'end_turn') {
    finalText = data.content
      .filter(b => b.type === 'text')
      .map(b => b.text)
      .join('');
    break;
  }

  if (data.stop_reason === 'tool_use') {
    const toolUseBlocks = data.content.filter(b => b.type === 'tool_use');
    const toolResults = [];

    for (const tb of toolUseBlocks) {
      let result;
      try {
        if (tb.name === 'salvar_perfil') {
          result = await executeSalvarPerfil(tb.input);
        } else if (tb.name === 'agendar_aula_experimental') {
          result = await executeAgendarAulaExperimental(tb.input);
        } else if (tb.name === 'handoff_humano') {
          result = await executeHandoffHumano(tb.input);
        } else {
          result = { status: 'error', mensagem: `Tool desconhecida: ${tb.name}` };
        }
      } catch (e) {
        result = { status: 'error', mensagem: e.message };
      }

      toolResults.push({
        type: 'tool_result',
        tool_use_id: tb.id,
        content: JSON.stringify(result),
      });
    }

    currentMessages.push({ role: 'user', content: toolResults });
    // Continua o loop para obter a resposta de texto final da IARA
    continue;
  }
}

if (!finalText) {
  finalText = 'Tive um problema técnico. Pode repetir sua mensagem?';
}

return [{ json: { remotejid, finalText } }];
